// Extract prefixed TELOS entries (M0/P0/S0/C0...) directly from raw file bullets, matching the
// `- **M0:** text`, `- **P0: text**`, and `- **G1: text**` styles. Section-splitting (parseSections)
// drops entries that live in a file's preamble above the first `## heading`, which is why Mission and
// Problems rendered empty while Goals worked. Scanning every line fixes that.
function parsePrefixedEntries(content: string, prefix: string): ParsedHeading[] {
  const re = new RegExp(`^\\s*[-*]\\s*\\*{0,2}(${prefix}\\d+[a-z]?)\\*{0,2}\\s*:\\s*(.+)$`, "i")
  const seen = new Set<string>()
  const out: ParsedHeading[] = []
  for (const line of content.split("\n")) {
    const m = line.match(re)
    if (!m) continue
    const id = m[1].toUpperCase()
    if (seen.has(id)) continue
    seen.add(id)
    out.push({ id, title: cleanInlineMarkdown(m[2]), body: "" })
  }
  return out
}

